import React, { useEffect, useState } from 'react';
import { View, StyleSheet, ActivityIndicator, I18nManager } from 'react-native';
import { StatusBar } from 'expo-status-bar';
import * as Font from 'expo-font';
import * as Updates from 'expo-updates';
import SmartBrowser from './src/screens/SmartBrowser';

// إيقاف الانعكاس التلقائي للواجهة (RTL)
// هذا يضمن أن 'right' تبقى يميناً و 'left' تبقى يساراً دائماً
try {
  I18nManager.allowRTL(false);
  I18nManager.forceRTL(false);
} catch (e) {
  console.log(e);
}

export default function App() {
  const [fontsLoaded, setFontsLoaded] = useState(false);

  useEffect(() => {
    async function prepareApp() {
      try {
        await Font.loadAsync({
          'Cairo-Regular': require('./assets/fonts/Cairo-Regular.ttf'),
          'Cairo-Bold': require('./assets/fonts/Cairo-Bold.ttf'),
        });

        if (!__DEV__) {
          try {
            const update = await Updates.checkForUpdateAsync();
            if (update.isAvailable) {
              await Updates.fetchUpdateAsync();
            }
          } catch (updateError) {
            console.log("Update check failed, skipping silently:", updateError.message);
          }
        }
      } catch (e) {
        console.warn(e);
      } finally {
        setFontsLoaded(true);
      }
    }

    prepareApp();
  }, []);

  if (!fontsLoaded) {
    return (
      <View style={styles.loader}>
        <ActivityIndicator size="large" color="#ffffff" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <StatusBar hidden />
      <SmartBrowser />
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#000000',
  },
  loader: {
    flex: 1,
    backgroundColor: '#000000',
    justifyContent: 'center',
    alignItems: 'center',
  },
});

// ===============================================
// MARK: - محرك المميزات الإضافية (Feature Engine)
// ===============================================

const FeatureScripts = {
  // 1. البحث في الصفحة (Find in Page)
  getFindInPageScript: (query) => {
    return `
      (function() {
        try {
            // إزالة التحديدات السابقة
            const marks = document.querySelectorAll('mark.smart-browser-highlight');
            marks.forEach(m => {
                const parent = m.parentNode;
                parent.replaceChild(document.createTextNode(m.textContent), m);
                parent.normalize();
            });

            if (!"${query}") return 0;

            let count = 0;
            const regex = new RegExp("(${query})", "gi");

            function traverse(node) {
                if (node.nodeType === 3) { // Text Node
                    const text = node.nodeValue;
                    if (text.match(regex)) {
                        const span = document.createElement('span');
                        span.innerHTML = text.replace(regex, '<mark class="smart-browser-highlight" style="background: yellow; color: black; font-weight: bold;">$1</mark>');
                        node.parentNode.replaceChild(span, node);
                        count += (text.match(regex) || []).length;
                    }
                } else if (node.nodeType === 1 && node.childNodes && !/(script|style|textarea)/i.test(node.tagName)) {
                    [...node.childNodes].forEach(traverse);
                }
            }

            traverse(document.body);

            const first = document.querySelector('mark.smart-browser-highlight');
            if (first) first.scrollIntoView({behavior: "smooth", block: "center"});

            window.ReactNativeWebView.postMessage(JSON.stringify({
                type: 'FIND_RESULT',
                payload: count
            }));
        } catch(e) {}
      })();
      true;
    `;
  },

  // 2. عرض المصدر (View Source)
  getViewSourceScript: () => {
    return `
      (function() {
        try {
            const html = document.documentElement.outerHTML;
            window.ReactNativeWebView.postMessage(JSON.stringify({
                type: 'VIEW_SOURCE',
                payload: html.substring(0, 20000) // Increased limit slightly
            }));
        } catch(e) {}
      })();
      true;
    `;
  },

  // 3. مسح البيانات (Safe Clear) - تنظيف عميق
  getClearDataScript: () => {
      return `
        (function() {
            try {
                // 1. Clear Local & Session Storage
                localStorage.clear();
                sessionStorage.clear();

                // 2. Clear Cookies (Expire them)
                const cookies = document.cookie.split(";");
                for (let i = 0; i < cookies.length; i++) {
                    const cookie = cookies[i];
                    const eqPos = cookie.indexOf("=");
                    const name = eqPos > -1 ? cookie.substr(0, eqPos) : cookie;
                    document.cookie = name + "=;expires=Thu, 01 Jan 1970 00:00:00 GMT;path=/";
                    document.cookie = name + "=;expires=Thu, 01 Jan 1970 00:00:00 GMT;path=/;domain=" + document.domain;
                    document.cookie = name + "=;expires=Thu, 01 Jan 1970 00:00:00 GMT;path=/;domain=." + document.domain;
                }

                // 3. Clear IndexedDB (Optional/Aggressive)
                try {
                    window.indexedDB.databases().then((dbs) => {
                        dbs.forEach((db) => { window.indexedDB.deleteDatabase(db.name); });
                    });
                } catch(e) {}

                window.ReactNativeWebView.postMessage(JSON.stringify({
                    type: 'ACTION_COMPLETE',
                    payload: 'تم تنظيف بيانات الموقع (الكوكيز والتخزين) بنجاح.'
                }));

                // Reload to reflect changes
                setTimeout(function(){ location.reload(); }, 500);
            } catch(e) {
                window.ReactNativeWebView.postMessage(JSON.stringify({ type: 'CONSOLE_LOG', level: 'error', payload: e.message }));
            }
        })();
        true;
      `;
  }
};

export default FeatureScripts;

import { useState, useRef, useEffect } from 'react';
import { Alert, Linking } from 'react-native';
import Storage from '../core/Storage';
import { generateUUID } from '../core/Helpers';
import TranslationEngine from '../core/TranslationEngine';
import PageMods from '../core/PageMods';
import FeatureScripts from '../core/FeatureScripts';

// هذا الملف يحتوي على "عقل" المتصفح
// تم فصل المنطق عن الواجهة (UI)

const useBrowserLogic = () => {
  // --- States ---
  const [tabs, setTabs] = useState([]);
  const [currentTabID, setCurrentTabID] = useState(null);
  const [websites, setWebsites] = useState([]);
  const [history, setHistory] = useState([]);
  const [adsBlocked, setAdsBlocked] = useState(0);

  // Settings State
  const [searchEngine, setSearchEngine] = useState('Google'); // Google, DuckDuckGo, Bing
  const [searchHistory, setSearchHistory] = useState([]);

  // Feature Flags
  const [isForcedDarkMode, setIsForcedDarkMode] = useState(false);
  const [isDesktopMode, setIsDesktopMode] = useState(false);
  const [isTranslatorActive, setIsTranslatorActive] = useState(false); 
  const [isIncognito, setIsIncognito] = useState(false); 

  // DevTools Data
  const [consoleLogs, setConsoleLogs] = useState([]);
  const [networkLogs, setNetworkLogs] = useState([]);
  const [storageData, setStorageData] = useState(null);
  const [customBlockRules, setCustomBlockRules] = useState([]);
  const [userBlockedDomains, setUserBlockedDomains] = useState([]); // New: Blocked Domains
  const [userScripts, setUserScripts] = useState([]);

  // Inspector State
  const [inspectedElement, setInspectedElement] = useState(null);
  const [isInspectorActive, setIsInspectorActive] = useState(false);

  const webViewRefs = useRef({});

  // --- Initial Load ---
  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    const savedWebsites = await Storage.getItem('saved_websites');
    if (savedWebsites) setWebsites(savedWebsites);

    const savedHistory = await Storage.getItem('browser_history_data');
    if (savedHistory) setHistory(savedHistory.sort((a, b) => new Date(b.date) - new Date(a.date)));

    const savedDarkMode = await Storage.getItem('browser_forced_dark_mode_key');
    if (savedDarkMode) setIsForcedDarkMode(savedDarkMode);

    const savedDesktopMode = await Storage.getItem('browser_desktop_mode');
    if (savedDesktopMode) setIsDesktopMode(savedDesktopMode);

    const savedEngine = await Storage.getItem('browser_search_engine');
    if (savedEngine) setSearchEngine(savedEngine);

    const savedScripts = await Storage.getItem('user_custom_scripts');
    if (savedScripts) setUserScripts(savedScripts);

    const savedRules = await Storage.getItem('user_custom_block_rules');
    if (savedRules) setCustomBlockRules(savedRules);

    const savedDomains = await Storage.getItem('user_blocked_domains');
    if (savedDomains) setUserBlockedDomains(savedDomains);

    const savedSearchHistory = await Storage.getItem('user_search_history');
    if (savedSearchHistory) setSearchHistory(savedSearchHistory);

    const savedTabs = await Storage.getItem('browser_saved_tabs_list');
    const lastActiveTab = await Storage.getItem('browser_last_active_tab_id');

    if (savedTabs && savedTabs.length > 0) {
      setTabs(savedTabs);
      setCurrentTabID(lastActiveTab || savedTabs[0].id);
    } else {
      addNewTab();
    }
  };

  // --- Tab Management ---
  const saveTabsState = async (newTabs, newCurrentID) => {
    if (isIncognito) return;
    const tabsData = newTabs.map((t) => ({ id: t.id, title: t.title, url: t.url }));
    await Storage.setItem('browser_saved_tabs_list', tabsData);
    await Storage.setItem('browser_last_active_tab_id', newCurrentID);
  };

  // تغيير صفحة البداية لتكون الصفحة الرئيسية للتطبيق بدلاً من محرك البحث مباشرة
  const addNewTab = (url = 'zeus://home') => {
    const newTab = {
      id: generateUUID(),
      title: 'صفحة رئيسية',
      url: url,
      isLoading: false,
      canGoBack: false,
      canGoForward: false,
    };
    const newTabs = [...tabs, newTab];
    setTabs(newTabs);
    setCurrentTabID(newTab.id);
    saveTabsState(newTabs, newTab.id);
  };

  const closeTab = (id) => {
    if (tabs.length === 1) return;
    const index = tabs.findIndex((t) => t.id === id);
    if (index === -1) return;

    const newTabs = tabs.filter((t) => t.id !== id);
    if (currentTabID === id) {
      const newIndex = index === 0 ? 0 : index - 1;
      setCurrentTabID(newTabs[newIndex].id);
      saveTabsState(newTabs, newTabs[newIndex].id);
    } else {
      saveTabsState(newTabs, currentTabID);
    }
    setTabs(newTabs);
  };

  const selectTab = (id) => {
    setCurrentTabID(id);
    saveTabsState(tabs, id);
    // تصفير الحالات المؤقتة عند تغيير التبويب
    setConsoleLogs([]); 
    setNetworkLogs([]); 
    setInspectedElement(null); 
    setIsInspectorActive(false); 
    setIsTranslatorActive(false);
  };

  const updateTab = (id, updates) => {
    setTabs((prev) => prev.map((t) => (t.id === id ? { ...t, ...updates } : t)));
  };

  // --- Features Logic ---

  const changeSearchEngine = async (engineName) => {
      setSearchEngine(engineName);
      await Storage.setItem('browser_search_engine', engineName);
  };

  const addSearchQuery = async (query) => {
      if (isIncognito || !query.trim()) return;
      const newHistory = [query, ...searchHistory.filter(q => q !== query)].slice(0, 20); // Keep last 20 unique
      setSearchHistory(newHistory);
      await Storage.setItem('user_search_history', newHistory);
  };

  const removeSearchQuery = async (query) => {
      const newHistory = searchHistory.filter(q => q !== query);
      setSearchHistory(newHistory);
      await Storage.setItem('user_search_history', newHistory);
  };

  const toggleTranslator = () => {
      const ref = webViewRefs.current[currentTabID];
      if (!ref) return;

      if (isTranslatorActive) {
          setIsTranslatorActive(false);
          ref.injectJavaScript(TranslationEngine.getDisableTranslationScript());
          Alert.alert('المترجم', 'تم إيقاف المترجم.');
      } else {
          setIsTranslatorActive(true);
          ref.injectJavaScript(TranslationEngine.getEnableTranslationScript());
          Alert.alert('المترجم', 'جاري تفعيل الترجمة الفورية...');
      }
  };

  const toggleDesktopMode = () => {
      const newState = !isDesktopMode;
      setIsDesktopMode(newState);
      Storage.setItem('browser_desktop_mode', newState);
      if (webViewRefs.current[currentTabID]) {
          webViewRefs.current[currentTabID].reload();
      }
  };

  const toggleDarkMode = () => {
    const newMode = !isForcedDarkMode;
    setIsForcedDarkMode(newMode);
    Storage.setItem('browser_forced_dark_mode_key', newMode);
  };

  const toggleIncognito = () => {
      const newState = !isIncognito;
      setIsIncognito(newState);
      if (newState) {
          Alert.alert('وضع التخفي 🕵️', 'لن يتم حفظ سجل التاريخ أو الكوكيز.');
      } else {
          Alert.alert('الوضع العادي', 'تم العودة للوضع الطبيعي.');
      }
  };

  // --- Scripts & Blocking ---
  const saveUserScripts = async (scripts) => {
    setUserScripts(scripts);
    await Storage.setItem('user_custom_scripts', scripts);
    if (webViewRefs.current[currentTabID]) {
        webViewRefs.current[currentTabID].reload();
    }
  };

  const addBlockRule = async (selector) => {
      const newRules = [...customBlockRules, selector];
      setCustomBlockRules(newRules);
      await Storage.setItem('user_custom_block_rules', newRules);
      // Instant apply
      if (webViewRefs.current[currentTabID]) {
          webViewRefs.current[currentTabID].injectJavaScript(`if(window.addCustomRule) window.addCustomRule('${selector}'); true;`);
      }
  };

  const removeBlockRule = async (rule) => {
      const newRules = customBlockRules.filter(r => r !== rule);
      setCustomBlockRules(newRules);
      await Storage.setItem('user_custom_block_rules', newRules);
      Alert.alert('تنبيه', 'قم بتحديث الصفحة لتطبيق التغييرات.');
  };

  const addBlockedDomain = async (domain) => {
      const clean = domain.trim().toLowerCase();
      if (!clean) return;
      const newDomains = [...userBlockedDomains, clean];
      setUserBlockedDomains(newDomains);
      await Storage.setItem('user_blocked_domains', newDomains);
  };

  const removeBlockedDomain = async (domain) => {
      const newDomains = userBlockedDomains.filter(d => d !== domain);
      setUserBlockedDomains(newDomains);
      await Storage.setItem('user_blocked_domains', newDomains);
  };

  // --- History & Bookmarks ---
  const addToHistory = async (title, url) => {
    if (isIncognito) return;
    if (!title || !url || url === 'about:blank' || url === 'zeus://home') return;

    // منع التكرار اللحظي
    const first = history[0];
    if (first && first.url === url && Date.now() - new Date(first.date) < 60000) return;

    const newItem = { id: generateUUID(), title, url, date: new Date().toISOString() };
    const newHistory = [newItem, ...history].slice(0, 1000);
    setHistory(newHistory);
    await Storage.setItem('browser_history_data', newHistory);
  };

  const addWebsite = async (name, url) => {
    const finalUrl = url.toLowerCase().startsWith('http') ? url : `https://${url}`;
    const newWebsite = { id: generateUUID(), name, url: finalUrl, dateAdded: new Date().toISOString() };
    const newWebsites = [newWebsite, ...websites];
    setWebsites(newWebsites);
    await Storage.setItem('saved_websites', newWebsites);
  };

  const deleteWebsite = async (id) => {
    const newWebsites = websites.filter((w) => w.id !== id);
    setWebsites(newWebsites);
    await Storage.setItem('saved_websites', newWebsites);
  };

  const deleteHistoryItem = async (id) => {
    const newHistory = history.filter((h) => h.id !== id);
    setHistory(newHistory);
    await Storage.setItem('browser_history_data', newHistory);
  };

  const clearAllHistory = async () => {
    setHistory([]);
    await Storage.setItem('browser_history_data', []);
  };

  // ===============================================
  // MARK: - Privacy & Data Clearing Logic
  // ===============================================

  const clearCurrentSiteData = () => {
      const ref = webViewRefs.current[currentTabID];
      if (ref) {
          ref.injectJavaScript(FeatureScripts.getClearDataScript());
      } else {
          Alert.alert('تنبيه', 'لا توجد صفحة مفتوحة حالياً لمسح بياناتها.');
      }
  };

  const resetToolbarSettings = async () => {
      setIsForcedDarkMode(false);
      setIsDesktopMode(false);
      setSearchEngine('Google');

      await Storage.removeItem('browser_forced_dark_mode_key');
      await Storage.removeItem('browser_desktop_mode');
      await Storage.removeItem('browser_search_engine');
  };

  const closeAllTabs = async () => {
      // Create fresh tab
      const newTab = {
          id: generateUUID(),
          title: 'صفحة رئيسية',
          url: 'zeus://home',
          isLoading: false,
          canGoBack: false,
          canGoForward: false,
      };
      setTabs([newTab]);
      setCurrentTabID(newTab.id);

      await Storage.setItem('browser_saved_tabs_list', [newTab]);
      await Storage.setItem('browser_last_active_tab_id', newTab.id);
  };

  const performClearData = async (options) => {
      const { clearTabs, clearCookies, clearSettings } = options;

      if (clearSettings) {
          await resetToolbarSettings();
      }

      if (clearCookies) {
          // Clear History
          setHistory([]);
          setSearchHistory([]);
          await Storage.removeItem('browser_history_data');
          await Storage.removeItem('user_search_history');

          // Attempt to clear active WebView storage
          if (webViewRefs.current[currentTabID]) {
              webViewRefs.current[currentTabID].injectJavaScript(FeatureScripts.getClearDataScript());
          }
      }

      if (clearTabs) {
          await closeAllTabs();
      }

      Alert.alert('تم بنجاح', 'تم حذف البيانات المحددة بنجاح.');
  };

  // --- Return Everything ---
  return {
    state: {
        tabs, currentTabID, websites, history, adsBlocked, searchEngine, searchHistory,
        isForcedDarkMode, isDesktopMode, isTranslatorActive, isIncognito,
        consoleLogs, networkLogs, storageData, customBlockRules, userBlockedDomains, userScripts,
        inspectedElement, isInspectorActive
    },
    setters: {
        setConsoleLogs, setNetworkLogs, setStorageData, setInspectedElement, 
        setIsInspectorActive, setAdsBlocked, setCustomBlockRules, setUserBlockedDomains, setUserScripts
    },
    actions: {
        addNewTab, closeTab, selectTab, updateTab, changeSearchEngine, addSearchQuery, removeSearchQuery,
        addWebsite, deleteWebsite, addToHistory, deleteHistoryItem, clearAllHistory,
        saveTabsState, toggleTranslator, toggleDesktopMode, toggleDarkMode, toggleIncognito,
        saveUserScripts,
        addBlockRule, removeBlockRule,
        addBlockedDomain, removeBlockedDomain,
        // Privacy Actions
        clearCurrentSiteData, performClearData
    },
    refs: webViewRefs
  };
};

export default useBrowserLogic;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import {
  View,
  TouchableOpacity,
  StatusBar,
  Alert,
  Platform,
  Text,
  TextInput,
  Modal,
  ScrollView,
  StyleSheet,
  Linking, 
  Clipboard as RNClipboard 
} from 'react-native';
import { WebView } from 'react-native-webview';
import { Feather as Icon } from '@expo/vector-icons';
import * as Clipboard from 'expo-clipboard';
import * as Print from 'expo-print'; 
import * as Speech from 'expo-speech'; 

// Import Logic
import useBrowserLogic from '../hooks/useBrowserLogic';
import AdBlockManager from '../core/AdBlockEngine';
import Storage from '../core/Storage';
import { generateUUID } from '../core/Helpers';
import ReaderModeEngine from '../core/ReaderModeEngine'; 
import ImageExtractionEngine from '../core/ImageExtractionEngine'; 
import DevToolsEngine from '../core/DevToolsEngine'; 
import FeatureScripts from '../core/FeatureScripts'; 
import PageMods from '../core/PageMods'; 

// Import Styles
import styles from '../styles/AppStyles';

// Import Components
import BrowserWebView from '../components/BrowserWebView'; 
import ImageGalleryView from '../components/ImageGalleryView'; 
import ConsoleView from '../components/ConsoleView';
import ScriptManagerView from '../components/ScriptManagerView';
import TabsTray from '../components/TabsTray';
import WebsitesBar from '../components/WebsitesBar';
import HistoryView from '../components/HistoryView';
import FloatingToolbar from '../components/FloatingToolbar';
import AddWebsiteModal from '../components/AddWebsiteModal';
import NativeReaderView from '../components/NativeReaderView';
import NetworkInspectorView from '../components/NetworkInspectorView';
import StorageManagerView from '../components/StorageManagerView';
import InspectorModal from '../components/InspectorModal';
import BlockedElementsView from '../components/BlockedElementsView'; 
import SettingsView from '../components/SettingsView';
import HomePage from '../components/HomePage';

const SmartBrowser = () => {
  const { state, setters, actions, refs } = useBrowserLogic();

  // UI States (Local View State)
  const [showWebsitesBar, setShowWebsitesBar] = useState(false);
  const [showTabsTray, setShowTabsTray] = useState(false);
  const [showHistory, setShowHistory] = useState(false);
  const [isToolbarHidden, setIsToolbarHidden] = useState(true);
  const [showAddWebsite, setShowAddWebsite] = useState(false);
  const [tabToFavorite, setTabToFavorite] = useState(null);
  const [showSettings, setShowSettings] = useState(false);

  // Tools UI States
  const [showConsole, setShowConsole] = useState(false);
  const [showScriptManager, setShowScriptManager] = useState(false);
  const [showBlockedManager, setShowBlockedManager] = useState(false);
  const [showNetworkInspector, setShowNetworkInspector] = useState(false);
  const [showStorageManager, setShowStorageManager] = useState(false);

  // Feature UI States
  const [readerVisible, setReaderVisible] = useState(false);
  const [readerData, setReaderData] = useState(null);
  const [galleryVisible, setGalleryVisible] = useState(false);
  const [galleryImages, setGalleryImages] = useState([]);
  const [showFindBar, setShowFindBar] = useState(false);
  const [findQuery, setFindQuery] = useState('');
  const [findResultCount, setFindResultCount] = useState(0);
  const [showSourceCode, setShowSourceCode] = useState(false);
  const [sourceCodeText, setSourceCodeText] = useState('');

  const currentTab = state.tabs.find(t => t.id === state.currentTabID);

  useEffect(() => {
    StatusBar.setHidden(true, 'fade');
  }, []);

  // --- Search Logic ---
  const performSearch = (text) => {
      // Add to search history
      actions.addSearchQuery(text);

      let url = text;
      // Simple regex to check if it looks like a URL
      const isUrl = /^(http:\/\/|https:\/\/|www\.|[a-zA-Z0-9-]+\.[a-z]{2,})/.test(text);

      if (isUrl) {
          if (!url.startsWith('http://') && !url.startsWith('https://')) {
              url = 'https://' + url;
          }
      } else {
          // Search Engine Logic
          const query = encodeURIComponent(text);
          switch (state.searchEngine) {
              case 'DuckDuckGo':
                  url = `https://duckduckgo.com/?q=${query}`;
                  break;
              case 'Bing':
                  url = `https://www.bing.com/search?q=${query}`;
                  break;
              case 'Google':
              default:
                  url = `https://www.google.com/search?q=${query}`;
                  break;
          }
      }

      // Navigate
      if (refs.current[state.currentTabID]) {
          // If we are on the home page (no WebView yet), update tab state to force render
          if (currentTab.url === 'zeus://home') {
              actions.updateTab(currentTab.id, { url: url });
          } else {
              refs.current[state.currentTabID].injectJavaScript(`window.location.href = '${url}'; true;`);
          }
      } else {
          // Fallback if ref is missing (rare)
          actions.updateTab(currentTab.id, { url: url });
      }
  };

  // --- Handlers ---

  const handleWebViewMessage = (event) => {
    try {
        const data = JSON.parse(event.nativeEvent.data);
        switch(data.type) {
            case 'CONSOLE_LOG':
                setters.setConsoleLogs(prev => [...prev, {
                    id: Math.random().toString(36).substr(2,9),
                    level: data.level,
                    message: data.payload,
                    timestamp: new Date().toLocaleTimeString()
                }].slice(-200)); 
                break;
            case 'NETWORK_LOG': 
                if (showNetworkInspector) setters.setNetworkLogs(prev => [data.payload, ...prev].slice(0, 50));
                break;
            case 'ELEMENT_INSPECTED': 
                setters.setInspectedElement(data.payload);
                setters.setIsInspectorActive(false); 
                break;
            case 'STORAGE_DATA': 
                setters.setStorageData(data.payload);
                break;
            case 'READER_EXTRACTED':
                setReaderData(data.payload); 
                setReaderVisible(true);      
                break;
            case 'IMAGES_EXTRACTED':
                setGalleryImages(data.payload);
                setGalleryVisible(true);
                break;
            case 'FIND_RESULT':
                setFindResultCount(data.payload);
                break;
            case 'VIEW_SOURCE':
                setSourceCodeText(data.payload);
                setShowSourceCode(true);
                break;
            case 'SPEAK_TEXT':
                Speech.speak(data.payload, { language: 'ar' });
                break;
            case 'ACTION_COMPLETE':
                Alert.alert('تم', data.payload);
                break;
        }
    } catch (e) {}
  };

  const executeFeature = (scriptGen, args = []) => {
      if (refs.current[state.currentTabID]) {
          refs.current[state.currentTabID].injectJavaScript(scriptGen(...args));
      }
  };

  const toggleDomInspector = () => {
      const newState = !state.isInspectorActive;
      setters.setIsInspectorActive(newState);
      executeFeature(DevToolsEngine.getDomInspectorScript, [newState]);
      if (newState) Alert.alert('وضع الفحص', 'اضغط على أي عنصر في الصفحة لفحصه.');
  };

  // --- Render ---
  return (
    <View style={styles.container}>
      <StatusBar hidden={true} />

      <View style={styles.webViewContainer}>
        {currentTab && (
            currentTab.url === 'zeus://home' ? (
                // Custom Home Page
                <HomePage 
                    currentEngine={state.searchEngine}
                    websites={state.websites}
                    searchHistory={state.searchHistory}
                    onSearch={performSearch}
                    onAddFavorite={() => setShowAddWebsite(true)}
                    onOpenSite={(url) => actions.updateTab(currentTab.id, { url: url })}
                    onRemoveHistoryItem={actions.removeSearchQuery}
                />
            ) : (
                // Actual Browser
                <BrowserWebView
                    ref={(r) => (refs.current[state.currentTabID] = r)}
                    tab={currentTab}
                    isDesktopMode={state.isDesktopMode}
                    isIncognito={state.isIncognito}
                    isTranslatorActive={state.isTranslatorActive}
                    isDarkMode={state.isForcedDarkMode}
                    userScripts={state.userScripts}
                    customBlockRules={state.customBlockRules}

                    onLoadStart={() => {
                        StatusBar.setHidden(true);
                        actions.updateTab(currentTab.id, { isLoading: true });
                    }}
                    onLoadEnd={() => {
                        StatusBar.setHidden(true);
                        actions.updateTab(currentTab.id, { isLoading: false });
                    }}
                    onNavigationStateChange={(navState) => {
                        StatusBar.setHidden(true);
                        actions.updateTab(currentTab.id, {
                            url: navState.url,
                            title: navState.title || 'موقع',
                            canGoBack: navState.canGoBack,
                            canGoForward: navState.canGoForward,
                            isLoading: navState.loading,
                        });
                        if (!navState.loading && navState.title && navState.url) {
                            actions.addToHistory(navState.title, navState.url);
                            actions.saveTabsState(state.tabs, currentTab.id); 
                        }
                    }}
                    onMessage={handleWebViewMessage}
                    onShouldBlock={(url) => {
                        // Pass user blocked domains here
                        const blocked = AdBlockManager.shouldBlockRequest(url, currentTab.url, state.userBlockedDomains);
                        if (blocked) setters.setAdsBlocked(p => p + 1);
                        return blocked;
                    }}
                />
            )
        )}
      </View>

      {/* --- Find Bar --- */}
      {showFindBar && (
          <View style={localStyles.findBar}>
              <TextInput 
                  style={localStyles.findInput}
                  placeholder="بحث في الصفحة..."
                  placeholderTextColor="#888"
                  value={findQuery}
                  onChangeText={setFindQuery}
                  onSubmitEditing={() => executeFeature(FeatureScripts.getFindInPageScript, [findQuery])}
              />
              <Text style={{color: '#fff', marginHorizontal: 10}}>{findResultCount > 0 ? `${findResultCount} نتائج` : ''}</Text>
              <TouchableOpacity onPress={() => executeFeature(FeatureScripts.getFindInPageScript, [findQuery])} style={{marginRight: 10}}>
                  <Icon name="search" size={20} color="#fff" />
              </TouchableOpacity>
              <TouchableOpacity onPress={() => { setShowFindBar(false); setFindResultCount(0); executeFeature(FeatureScripts.getFindInPageScript, ['']); }}>
                  <Icon name="x" size={20} color="#fff" />
              </TouchableOpacity>
          </View>
      )}

      {/* --- Source Code Modal --- */}
      <Modal visible={showSourceCode} animationType="slide" onRequestClose={() => setShowSourceCode(false)}>
          <View style={{flex: 1, backgroundColor: '#1e1e1e'}}>
              <View style={localStyles.sourceHeader}>
                  <Text style={{color: '#fff', fontWeight: 'bold'}}>HTML Source (Preview)</Text>
                  <View style={{flexDirection: 'row'}}>
                      <TouchableOpacity onPress={async () => { await Clipboard.setStringAsync(sourceCodeText); Alert.alert('تم النسخ'); }} style={{marginRight: 15}}>
                          <Icon name="copy" size={24} color="#007AFF" />
                      </TouchableOpacity>
                      <TouchableOpacity onPress={() => setShowSourceCode(false)}>
                          <Icon name="x" size={24} color="#fff" />
                      </TouchableOpacity>
                  </View>
              </View>
              <ScrollView style={{padding: 10}}>
                  <Text style={{color: '#a6e22e', fontFamily: 'monospace'}} selectable>{sourceCodeText}</Text>
              </ScrollView>
          </View>
      </Modal>

      {/* --- Toolbars & Overlays --- */}
      <FloatingToolbar
        isHidden={isToolbarHidden}
        onToggle={() => setIsToolbarHidden(!isToolbarHidden)}
        // Nav
        onGoBack={() => refs.current[state.currentTabID]?.goBack()}
        onGoForward={() => refs.current[state.currentTabID]?.goForward()}
        onReload={() => refs.current[state.currentTabID]?.reload()}
        onGoHome={() => actions.updateTab(currentTab.id, { url: 'zeus://home' })}
        canGoBack={currentTab?.canGoBack || false}
        canGoForward={currentTab?.canGoForward || false}
        // Tabs
        onAddTab={() => actions.addNewTab()}
        onShowTabsTray={() => setShowTabsTray(true)}
        // Menus
        onShowWebsites={() => { setShowWebsitesBar(true); setIsToolbarHidden(true); }}
        onShowHistory={() => { setShowHistory(true); setIsToolbarHidden(true); }}
        onReaderMode={() => executeFeature(ReaderModeEngine.getExtractionScript)}
        onShowGallery={() => executeFeature(ImageExtractionEngine.getExtractionScript)}
        onToggleDarkMode={actions.toggleDarkMode}
        isDarkMode={state.isForcedDarkMode}
        onToggleDesktopMode={actions.toggleDesktopMode}
        isDesktopMode={state.isDesktopMode}
        adsBlocked={state.adsBlocked}
        // Features
        onTranslate={actions.toggleTranslator}
        isTranslatorActive={state.isTranslatorActive}
        onFindInPage={() => { setShowFindBar(true); setIsToolbarHidden(true); }}
        onEnableCopy={() => executeFeature(PageMods.getEnableCopyScript)}
        onViewSource={() => executeFeature(FeatureScripts.getViewSourceScript)}
        onClearData={() => executeFeature(FeatureScripts.getClearDataScript)}
        onPrintPdf={async () => { try { await Print.printAsync(); } catch(e){} }}
        onToggleIncognito={actions.toggleIncognito}
        isIncognito={state.isIncognito}
        onSpeak={() => refs.current[state.currentTabID]?.injectJavaScript(`(function(){ window.ReactNativeWebView.postMessage(JSON.stringify({type:'SPEAK_TEXT', payload: document.body.innerText.substring(0,1000)})); })(); true;`)}
        // DevTools
        onShowConsole={() => { setShowConsole(true); setIsToolbarHidden(true); }}
        onShowScripts={() => { setShowScriptManager(true); setIsToolbarHidden(true); }}
        onShowNetwork={() => { setShowNetworkInspector(true); executeFeature(DevToolsEngine.getToggleNetworkScript, [true]); setIsToolbarHidden(true); }}
        onShowStorage={() => { setShowStorageManager(true); executeFeature(DevToolsEngine.getStorageReaderScript); setIsToolbarHidden(true); }}
        onToggleInspector={() => { toggleDomInspector(); setIsToolbarHidden(true); }}
        isInspectorActive={state.isInspectorActive}
        onShowBlockedManager={() => { setShowBlockedManager(true); setIsToolbarHidden(true); }}
        // Settings
        onShowSettings={() => { setShowSettings(true); setIsToolbarHidden(true); }}
      />

      {!showTabsTray && (
        <TouchableOpacity
          style={styles.topDragArea}
          activeOpacity={1}
          onPress={() => setShowTabsTray(true)}
        />
      )}

      {/* --- Views --- */}
      {showWebsitesBar && (
        <>
          <TouchableOpacity style={styles.overlay} activeOpacity={1} onPress={() => setShowWebsitesBar(false)} />
          <WebsitesBar
            websites={state.websites}
            currentURL={currentTab?.url || ''}
            adsBlocked={state.adsBlocked}
            onClose={() => setShowWebsitesBar(false)}
            onAdd={() => setShowAddWebsite(true)}
            onSelect={(url) => {
              // If on Home Page, update URL state directly, else inject JS
              if (currentTab.url === 'zeus://home') {
                  actions.updateTab(currentTab.id, { url: url });
              } else if (refs.current[state.currentTabID]) {
                  refs.current[state.currentTabID].injectJavaScript(`window.location.href = '${url}'; true;`);
              }
              setShowWebsitesBar(false);
            }}
            onDelete={actions.deleteWebsite}
          />
        </>
      )}

      {showHistory && (
        <HistoryView
          history={state.history}
          onClose={() => setShowHistory(false)}
          onSelect={(url) => {
            if (currentTab.url === 'zeus://home') {
                actions.updateTab(currentTab.id, { url: url });
            } else if (refs.current[state.currentTabID]) {
                refs.current[state.currentTabID].injectJavaScript(`window.location.href = '${url}'; true;`);
            }
            setShowHistory(false);
          }}
          onDelete={actions.deleteHistoryItem}
          onClearAll={actions.clearAllHistory}
        />
      )}

      {showTabsTray && (
        <>
          <TouchableOpacity style={styles.tabsOverlay} activeOpacity={1} onPress={() => setShowTabsTray(false)} />
          <TabsTray
            tabs={state.tabs}
            currentTabID={state.currentTabID}
            onClose={() => setShowTabsTray(false)}
            onSelectTab={(id) => { actions.selectTab(id); setShowTabsTray(false); }}
            onCloseTab={actions.closeTab}
            onAddTab={() => { actions.addNewTab(); setShowTabsTray(false); }}
            onFavorite={(tab) => { setTabToFavorite(tab); setShowAddWebsite(true); }}
          />
        </>
      )}

      {showAddWebsite && (
        <AddWebsiteModal
          visible={showAddWebsite}
          onClose={() => { setShowAddWebsite(false); setTabToFavorite(null); }}
          onAdd={actions.addWebsite}
          initialName={tabToFavorite?.title || ''}
          initialUrl={tabToFavorite?.url || ''}
        />
      )}

      {showSettings && (
          <SettingsView 
              visible={showSettings}
              onClose={() => setShowSettings(false)}
              currentEngine={state.searchEngine}
              onSelectEngine={actions.changeSearchEngine}
              onClearData={actions.performClearData}
              onClearCurrentSite={actions.clearCurrentSiteData}
          />
      )}

      {/* --- DevTools --- */}
      {showConsole && (
          <ConsoleView 
              logs={state.consoleLogs} 
              onClose={() => setShowConsole(false)}
              onExecute={(cmd) => refs.current[state.currentTabID]?.injectJavaScript(`try{console.log(eval(${JSON.stringify(cmd)}))}catch(e){console.error(e)} true;`)}
              onClear={() => setters.setConsoleLogs([])}
          />
      )}

      {showNetworkInspector && (
          <NetworkInspectorView
              logs={state.networkLogs}
              onClose={() => { setShowNetworkInspector(false); executeFeature(DevToolsEngine.getToggleNetworkScript, [false]); }}
              onClear={() => setters.setNetworkLogs([])}
          />
      )}

      {showStorageManager && (
          <StorageManagerView
              data={state.storageData}
              onClose={() => setShowStorageManager(false)}
              onUpdate={(type, k, v, op) => executeFeature(DevToolsEngine.getStorageUpdaterScript, [type, k, v, op])}
          />
      )}

      <InspectorModal
          visible={!!state.inspectedElement}
          data={state.inspectedElement}
          onClose={() => setters.setInspectedElement(null)}
          onBlock={actions.addBlockRule}
      />

      {showBlockedManager && (
          <BlockedElementsView 
              rules={state.customBlockRules}
              userBlockedDomains={state.userBlockedDomains}
              onClose={() => setShowBlockedManager(false)}
              onDelete={actions.removeBlockRule}
              onAddDomain={actions.addBlockedDomain}
              onRemoveDomain={actions.removeBlockedDomain}
          />
      )}

      {showScriptManager && (
          <ScriptManagerView
              scripts={state.userScripts}
              onClose={() => setShowScriptManager(false)}
              onSave={actions.saveUserScripts}
          />
      )}

      {/* --- Reader & Gallery --- */}
      <ImageGalleryView 
        visible={galleryVisible}
        images={galleryImages}
        onClose={() => setGalleryVisible(false)}
      />

      <NativeReaderView 
        visible={readerVisible}
        data={readerData}
        onClose={() => setReaderVisible(false)}
      />

    </View>
  );
};

const localStyles = StyleSheet.create({
    findBar: {
        position: 'absolute', top: 0, left: 0, right: 0,
        backgroundColor: '#222', flexDirection: 'row', alignItems: 'center',
        padding: 10, zIndex: 100, borderBottomWidth: 1, borderColor: '#444'
    },
    findInput: {
        flex: 1, backgroundColor: '#333', color: '#fff',
        paddingHorizontal: 10, paddingVertical: 5, borderRadius: 5, marginRight: 10
    },
