        flexDirection: 'row', justifyContent: 'space-between', padding: 15,
        backgroundColor: '#1a1a1a', borderBottomWidth: 1, borderColor: '#333'
    }
});

export default SmartBrowser;

import React, { useRef, useEffect, useState } from 'react';
import { View, Text, TouchableOpacity, Modal, StyleSheet, Animated, ScrollView, Alert } from 'react-native';
import { Feather as Icon } from '@expo/vector-icons';

const SEARCH_ENGINES = [
    { name: 'Google', color: '#4285F4' }, 
    { name: 'DuckDuckGo', color: '#DE5833' },
    { name: 'Bing', color: '#008373' },
];

const SettingsView = ({ visible, onClose, currentEngine, onSelectEngine, onClearData, onClearCurrentSite }) => {
    const slideAnim = useRef(new Animated.Value(300)).current;

    // حالة الخيارات المختارة للحذف
    const [selectedOptions, setSelectedOptions] = useState({
        tabs: false,
        cookies: false,
        settings: false
    });

    useEffect(() => {
        if (visible) {
            Animated.spring(slideAnim, {
                toValue: 0,
                useNativeDriver: true,
                friction: 8
            }).start();
        } else {
            Animated.timing(slideAnim, {
                toValue: 300,
                duration: 200,
                useNativeDriver: true
            }).start();
        }
    }, [visible]);

    const toggleOption = (key) => {
        setSelectedOptions(prev => ({ ...prev, [key]: !prev[key] }));
    };

    const toggleAll = () => {
        const allSelected = selectedOptions.tabs && selectedOptions.cookies && selectedOptions.settings;
        if (allSelected) {
            setSelectedOptions({ tabs: false, cookies: false, settings: false });
        } else {
            setSelectedOptions({ tabs: true, cookies: true, settings: true });
        }
    };

    const handleClearSelected = () => {
        const hasSelection = Object.values(selectedOptions).some(v => v);
        if (!hasSelection) {
            Alert.alert('تنبيه', 'الرجاء اختيار عنصر واحد على الأقل للحذف.');
            return;
        }

        Alert.alert(
            'تأكيد الحذف',
            'هل أنت متأكد من رغبتك في حذف البيانات المحددة؟ لا يمكن التراجع عن هذا الإجراء.',
            [
                { text: 'إلغاء', style: 'cancel' },
                { 
                    text: 'حذف البيانات', 
                    style: 'destructive',
                    onPress: () => {
                        onClearData(selectedOptions);
                        onClose();
                    }
                }
            ]
        );
    };

    const handleClearCurrentSite = () => {
        Alert.alert(
            'مسح بيانات الموقع الحالي',
            'سيتم مسح جميع الكوكيز والبيانات المخزنة لهذه الصفحة فقط. سيتم إعادة تحميل الصفحة.',
            [
                { text: 'إلغاء', style: 'cancel' },
                { 
                    text: 'مسح وإعادة تحميل', 
                    style: 'destructive',
                    onPress: () => {
                        onClearCurrentSite();
                        onClose();
                    }
                }
            ]
        );
    };

    if (!visible) return null;

    return (
        <Modal transparent visible={visible} onRequestClose={onClose} animationType="none">
            <View style={styles.overlay}>
                <TouchableOpacity style={styles.backdrop} onPress={onClose} activeOpacity={1} />

                <Animated.View style={[styles.container, { transform: [{ translateY: slideAnim }] }]}>
                    {/* Handle Bar */}
                    <View style={styles.handle} />

                    <View style={styles.header}>
                        <Text style={styles.title}>الإعدادات</Text>
                        <TouchableOpacity onPress={onClose} style={styles.closeBtn}>
                            <Icon name="x" size={24} color="#ccc" />
                        </TouchableOpacity>
                    </View>

                    <ScrollView style={styles.content} showsVerticalScrollIndicator={false}>

                        {/* 1. Search Engine */}
                        <View style={styles.section}>
                            <Text style={styles.sectionTitle}>محرك البحث المفضل</Text>
                            <View style={styles.engineList}>
                                {SEARCH_ENGINES.map((engine) => (
                                    <TouchableOpacity 
                                        key={engine.name} 
                                        style={[
                                            styles.engineOption, 
                                            currentEngine === engine.name && styles.engineSelected
                                        ]}
                                        onPress={() => onSelectEngine(engine.name)}
                                    >
                                        <View style={[styles.radioCircle, currentEngine === engine.name && { borderColor: engine.color }]}>
                                            {currentEngine === engine.name && <View style={[styles.radioDot, { backgroundColor: engine.color }]} />}
                                        </View>
                                        <Text style={[styles.engineName, currentEngine === engine.name && { color: engine.color }]}>
                                            {engine.name}
                                        </Text>
                                        {currentEngine === engine.name && <Icon name="check" size={18} color={engine.color} style={{marginLeft: 'auto'}} />}
                                    </TouchableOpacity>
                                ))}
                            </View>
                        </View>

                        {/* 2. Privacy & Data Clearing */}
                        <View style={styles.section}>
                            <Text style={styles.sectionTitle}>الخصوصية ومسح البيانات</Text>
                            <View style={styles.privacyContainer}>

                                {/* Header Row: Select All */}
                                <View style={styles.privacyHeader}>
                                    <Text style={styles.privacySubtitle}>حدد ما تريد حذفه:</Text>
                                    <TouchableOpacity onPress={toggleAll}>
                                        <Text style={styles.selectAllText}>
                                            {(selectedOptions.tabs && selectedOptions.cookies && selectedOptions.settings) ? 'إلغاء التحديد' : 'تحديد الكل'}
                                        </Text>
                                    </TouchableOpacity>
                                </View>

                                {/* Checkbox Items */}
                                <TouchableOpacity style={styles.checkboxRow} onPress={() => toggleOption('tabs')}>
                                    <View style={[styles.checkbox, selectedOptions.tabs && styles.checkboxChecked]}>
                                        {selectedOptions.tabs && <Icon name="check" size={14} color="#fff" />}
                                    </View>
                                    <Text style={styles.checkboxLabel}>التبويبات المفتوحة</Text>
                                    <Icon name="layers" size={16} color="#888" style={{marginLeft: 'auto'}} />
                                </TouchableOpacity>

                                <TouchableOpacity style={styles.checkboxRow} onPress={() => toggleOption('cookies')}>
                                    <View style={[styles.checkbox, selectedOptions.cookies && styles.checkboxChecked]}>
                                        {selectedOptions.cookies && <Icon name="check" size={14} color="#fff" />}
                                    </View>
                                    <Text style={styles.checkboxLabel}>الكوكيز وبيانات المواقع (Login)</Text>
                                    <Icon name="key" size={16} color="#888" style={{marginLeft: 'auto'}} />
                                </TouchableOpacity>

                                <TouchableOpacity style={styles.checkboxRow} onPress={() => toggleOption('settings')}>
                                    <View style={[styles.checkbox, selectedOptions.settings && styles.checkboxChecked]}>
                                        {selectedOptions.settings && <Icon name="check" size={14} color="#fff" />}
                                    </View>
                                    <Text style={styles.checkboxLabel}>إعدادات شريط الأدوات (Preferences)</Text>
                                    <Icon name="sliders" size={16} color="#888" style={{marginLeft: 'auto'}} />
                                </TouchableOpacity>

                                {/* Delete Button */}
                                <TouchableOpacity 
                                    style={[styles.deleteButton, !Object.values(selectedOptions).some(v=>v) && {opacity: 0.5}]} 
                                    onPress={handleClearSelected}
                                >
                                    <Icon name="trash-2" size={18} color="#fff" style={{marginRight: 8}} />
                                    <Text style={styles.deleteButtonText}>حذف البيانات المحددة</Text>
                                </TouchableOpacity>

                                <View style={styles.divider} />

                                {/* Clear Current Site Data */}
                                <TouchableOpacity style={styles.clearCurrentButton} onPress={handleClearCurrentSite}>
                                    <Icon name="zap" size={18} color="#FF9800" style={{marginRight: 8}} />
                                    <Text style={styles.clearCurrentText}>مسح بيانات الصفحة الحالية فقط</Text>
                                </TouchableOpacity>

                            </View>
                        </View>

                        {/* 3. General Info */}
                        <View style={styles.section}>
                            <Text style={styles.sectionTitle}>عام</Text>
                            <View style={styles.settingRow}>
                                <View style={styles.iconBox}><Icon name="info" size={20} color="#fff" /></View>
                                <Text style={styles.settingText}>عن المتصفح</Text>
                                <Text style={styles.versionText}>v1.0.0</Text>
                            </View>
                        </View>

                        <View style={{height: 50}} />
                    </ScrollView>
                </Animated.View>
            </View>
        </Modal>
    );
};

