    setTabs(newTabs);
  };

  const selectTab = (id) => {
    setCurrentTabID(id);
    saveTabsState(tabs, id);
    // تصفير الحالات المؤقتة عند تغيير التبويب
    setConsoleLogs([]); 
    setNetworkLogs([]); 
    setInspectedElement(null); 
    setIsInspectorActive(false); 
    setIsTranslatorActive(false);
  };

  const updateTab = (id, updates) => {
    setTabs((prev) => prev.map((t) => (t.id === id ? { ...t, ...updates } : t)));
  };

  // --- Features Logic ---

  const changeSearchEngine = async (engineName) => {
      setSearchEngine(engineName);
      await Storage.setItem('browser_search_engine', engineName);
  };

  const addSearchQuery = async (query) => {
      if (isIncognito || !query.trim()) return;
      const newHistory = [query, ...searchHistory.filter(q => q !== query)].slice(0, 20); // Keep last 20 unique
      setSearchHistory(newHistory);
      await Storage.setItem('user_search_history', newHistory);
  };

  const removeSearchQuery = async (query) => {
      const newHistory = searchHistory.filter(q => q !== query);
      setSearchHistory(newHistory);
      await Storage.setItem('user_search_history', newHistory);
  };

  const toggleTranslator = () => {
      const ref = webViewRefs.current[currentTabID];
      if (!ref) return;

      if (isTranslatorActive) {
          setIsTranslatorActive(false);
          ref.injectJavaScript(TranslationEngine.getDisableTranslationScript());
          Alert.alert('المترجم', 'تم إيقاف المترجم.');
      } else {
          setIsTranslatorActive(true);
          ref.injectJavaScript(TranslationEngine.getEnableTranslationScript());
          Alert.alert('المترجم', 'جاري تفعيل الترجمة الفورية...');
      }
  };

  const toggleDesktopMode = () => {
      const newState = !isDesktopMode;
      setIsDesktopMode(newState);
      Storage.setItem('browser_desktop_mode', newState);
      if (webViewRefs.current[currentTabID]) {
          webViewRefs.current[currentTabID].reload();
      }
  };

  const toggleDarkMode = () => {
    const newMode = !isForcedDarkMode;
    setIsForcedDarkMode(newMode);
    Storage.setItem('browser_forced_dark_mode_key', newMode);
  };

  const toggleIncognito = () => {
      const newState = !isIncognito;
      setIsIncognito(newState);
      if (newState) {
          Alert.alert('وضع التخفي 🕵️', 'لن يتم حفظ سجل التاريخ أو الكوكيز.');
      } else {
          Alert.alert('الوضع العادي', 'تم العودة للوضع الطبيعي.');
      }
  };

  // --- Scripts & Blocking ---
  const saveUserScripts = async (scripts) => {
    setUserScripts(scripts);
    await Storage.setItem('user_custom_scripts', scripts);
    if (webViewRefs.current[currentTabID]) {
        webViewRefs.current[currentTabID].reload();
    }
  };

  const addBlockRule = async (selector) => {
      const newRules = [...customBlockRules, selector];
      setCustomBlockRules(newRules);
      await Storage.setItem('user_custom_block_rules', newRules);
      // Instant apply
      if (webViewRefs.current[currentTabID]) {
          webViewRefs.current[currentTabID].injectJavaScript(`if(window.addCustomRule) window.addCustomRule('${selector}'); true;`);
      }
  };

  const removeBlockRule = async (rule) => {
      const newRules = customBlockRules.filter(r => r !== rule);
      setCustomBlockRules(newRules);
      await Storage.setItem('user_custom_block_rules', newRules);
      Alert.alert('تنبيه', 'قم بتحديث الصفحة لتطبيق التغييرات.');
  };

  const addBlockedDomain = async (domain) => {
      const clean = domain.trim().toLowerCase();
      if (!clean) return;
      const newDomains = [...userBlockedDomains, clean];
      setUserBlockedDomains(newDomains);
      await Storage.setItem('user_blocked_domains', newDomains);
  };

  const removeBlockedDomain = async (domain) => {
      const newDomains = userBlockedDomains.filter(d => d !== domain);
      setUserBlockedDomains(newDomains);
      await Storage.setItem('user_blocked_domains', newDomains);
  };

  // --- History & Bookmarks ---
  const addToHistory = async (title, url) => {
    if (isIncognito) return;
    if (!title || !url || url === 'about:blank' || url === 'zeus://home') return;

    // منع التكرار اللحظي
    const first = history[0];
    if (first && first.url === url && Date.now() - new Date(first.date) < 60000) return;

    const newItem = { id: generateUUID(), title, url, date: new Date().toISOString() };
    const newHistory = [newItem, ...history].slice(0, 1000);
    setHistory(newHistory);
    await Storage.setItem('browser_history_data', newHistory);
  };

  const addWebsite = async (name, url) => {
    const finalUrl = url.toLowerCase().startsWith('http') ? url : `https://${url}`;
    const newWebsite = { id: generateUUID(), name, url: finalUrl, dateAdded: new Date().toISOString() };
    const newWebsites = [newWebsite, ...websites];
    setWebsites(newWebsites);
    await Storage.setItem('saved_websites', newWebsites);
  };

  const deleteWebsite = async (id) => {
    const newWebsites = websites.filter((w) => w.id !== id);
    setWebsites(newWebsites);
    await Storage.setItem('saved_websites', newWebsites);
  };

  const deleteHistoryItem = async (id) => {
    const newHistory = history.filter((h) => h.id !== id);
    setHistory(newHistory);
    await Storage.setItem('browser_history_data', newHistory);
  };

  const clearAllHistory = async () => {
    setHistory([]);
    await Storage.setItem('browser_history_data', []);
  };

  // ===============================================
  // MARK: - Privacy & Data Clearing Logic (FACTORY RESET)
  // ===============================================

  const clearCurrentSiteData = () => {
      const ref = webViewRefs.current[currentTabID];
      if (ref) {
          ref.injectJavaScript(FeatureScripts.getClearDataScript());
      } else {
          Alert.alert('تنبيه', 'لا توجد صفحة مفتوحة حالياً لمسح بياناتها.');
      }
  };

  // حساب المساحة المستهلكة
  const getStorageUsage = async () => {
      try {
          // حساب حجم AsyncStorage (مفاتيح التطبيق فقط)
          const keys = await AsyncStorage.getAllKeys();
          if (keys.length === 0) return 0;

          const stores = await AsyncStorage.multiGet(keys);
          let totalBytes = 0;

          stores.forEach(([key, value]) => {
              if(value) totalBytes += value.length * 2; // JS strings are UTF-16 roughly
          });

          // تحويل للبايت
          return totalBytes;
      } catch(e) {
          return 0;
      }
  };

  const performClearData = async (options) => {
      const { clearTabs, clearCookies, clearSettings } = options;

      // إذا تم تحديد الكل، نقوم بفرمتة كاملة (Nuclear Option)
      if (clearTabs && clearCookies && clearSettings) {
          try {
             // 1. مسح كل شيء من الذاكرة الدائمة
             await AsyncStorage.clear();

             // 2. تصفير الحالة في الذاكرة المؤقتة (RAM)
             setWebsites([]);
             setHistory([]);
             setSearchHistory([]);
             setUserScripts([]);
             setCustomBlockRules([]);
             setUserBlockedDomains([]);
             setIsForcedDarkMode(false);
             setIsDesktopMode(false);
             setSearchEngine('Google');

             // 3. إعادة إنشاء تبويب جديد نظيف
             const newTab = {
                id: generateUUID(),
                title: 'صفحة رئيسية',
                url: 'zeus://home',
                isLoading: false,
                canGoBack: false,
                canGoForward: false,
            };
            setTabs([newTab]);
            setCurrentTabID(newTab.id);

            // حقن كود تنظيف في الصفحة الحالية إن وجدت
            if (webViewRefs.current[currentTabID]) {
                webViewRefs.current[currentTabID].injectJavaScript(`localStorage.clear(); sessionStorage.clear(); document.cookie.split(";").forEach(function(c) { document.cookie = c.replace(/^ +/, "").replace(/=.*/, "=;expires=" + new Date().toUTCString() + ";path=/"); }); location.reload();`);
            }

            Alert.alert('تمت الفرمتة', 'تم حذف جميع بيانات التطبيق بنجاح وكأنك قمت بتثبيته للتو.');
          } catch(e) {
              Alert.alert('خطأ', 'حدث خطأ أثناء محاولة مسح البيانات.');
          }
          return;
      }

      // الحذف الجزئي
      if (clearSettings) {
          setIsForcedDarkMode(false);
          setIsDesktopMode(false);
          setSearchEngine('Google');
          setAdsBlocked(0);
          await Storage.removeItem('browser_forced_dark_mode_key');
          await Storage.removeItem('browser_desktop_mode');
          await Storage.removeItem('browser_search_engine');
      }

      if (clearCookies) {
          setHistory([]);
          setSearchHistory([]);
          await Storage.removeItem('browser_history_data');
          await Storage.removeItem('user_search_history');
          if (webViewRefs.current[currentTabID]) {
              webViewRefs.current[currentTabID].injectJavaScript(FeatureScripts.getClearDataScript());
          }
      }

      if (clearTabs) {
          const newTab = {
              id: generateUUID(),
              title: 'صفحة رئيسية',
              url: 'zeus://home',
              isLoading: false,
              canGoBack: false,
              canGoForward: false,
          };
          setTabs([newTab]);
          setCurrentTabID(newTab.id);
          await Storage.setItem('browser_saved_tabs_list', [newTab]);
          await Storage.setItem('browser_last_active_tab_id', newTab.id);
      }

      Alert.alert('تم', 'تم حذف البيانات المحددة.');
  };

  // --- Return Everything ---
  return {
    state: {
        tabs, currentTabID, websites, history, adsBlocked, searchEngine, searchHistory,
        isForcedDarkMode, isDesktopMode, isTranslatorActive, isIncognito,
        consoleLogs, networkLogs, storageData, customBlockRules, userBlockedDomains, userScripts,
        inspectedElement, isInspectorActive
    },
    setters: {
        setConsoleLogs, setNetworkLogs, setStorageData, setInspectedElement, 
        setIsInspectorActive, setAdsBlocked, setCustomBlockRules, setUserBlockedDomains, setUserScripts
    },
    actions: {
        addNewTab, closeTab, selectTab, updateTab, changeSearchEngine, addSearchQuery, removeSearchQuery,
        addWebsite, deleteWebsite, addToHistory, deleteHistoryItem, clearAllHistory,
        saveTabsState, toggleTranslator, toggleDesktopMode, toggleDarkMode, toggleIncognito,
        saveUserScripts,
        addBlockRule, removeBlockRule,
        addBlockedDomain, removeBlockedDomain,
        // Privacy Actions
        clearCurrentSiteData, performClearData, getStorageUsage // Export function
    },
    refs: webViewRefs
  };
};

export default useBrowserLogic;

import React, { useRef, useEffect, useState } from 'react';
import { View, Text, TouchableOpacity, Modal, StyleSheet, Animated, ScrollView, Alert, Switch, Dimensions } from 'react-native';
import { Feather as Icon } from '@expo/vector-icons';
import useBrowserLogic from '../hooks/useBrowserLogic'; // لاستخدام دالة الحجم

const { height } = Dimensions.get('window');

const SEARCH_ENGINES = [
    { name: 'Google', icon: 'chrome', color: '#4285F4' }, 
    { name: 'DuckDuckGo', icon: 'target', color: '#DE5833' },
    { name: 'Bing', icon: 'globe', color: '#008373' },
];

const SettingsView = ({ visible, onClose, currentEngine, onSelectEngine, onClearData, onClearCurrentSite }) => {
    const slideAnim = useRef(new Animated.Value(height)).current;

    // Storage Size State
    const [storageSize, setStorageSize] = useState('0 KB');
    const { actions } = useBrowserLogic(); // Hacky way to get logic if not passed props, better to pass in props but logic file is separate. 
    // Note: Since SettingsView is a dumb component, we should rely on props or context.
    // However, for calculating size on mount, we can do a quick calculation or assume logic passed down.
    // Let's assume we fetch size inside useEffect.

    // خيارات الحذف
    const [clearOpts, setClearOpts] = useState({ history: false, cookies: false, tabs: false, all: false });

    useEffect(() => {
        if (visible) {
            calculateSize();
            Animated.spring(slideAnim, {
                toValue: 0,
                useNativeDriver: true,
                friction: 8
            }).start();
        } else {
            Animated.timing(slideAnim, {
                toValue: height,
                duration: 250,
                useNativeDriver: true
            }).start();
        }
    }, [visible]);

    const calculateSize = async () => {
        // بما أننا لا نستطيع الوصول لـ actions مباشرة هنا بسهولة دون تمريرها، 
        // سنعتمد على أن الأب يمرر دالة أو نستخدم AsyncStorage مباشرة للحساب هنا للعرض
        const AsyncSto = require('@react-native-async-storage/async-storage').default;
        try {
            const keys = await AsyncSto.getAllKeys();
            const stores = await AsyncSto.multiGet(keys);
            let bytes = 0;
            stores.forEach(([k, v]) => { if(v) bytes += v.length * 2; }); // Estimate

            if (bytes > 1024 * 1024) {
                setStorageSize((bytes / (1024 * 1024)).toFixed(2) + ' MB');
            } else {
                setStorageSize((bytes / 1024).toFixed(2) + ' KB');
            }
        } catch(e) {
            setStorageSize('Unknown');
        }
    };

    const handleClearAction = () => {
        if (clearOpts.all) {
            Alert.alert(
                'تصفير التطبيق بالكامل',
                'تحذير: سيتم حذف كل شيء (المواقع المحفوظة، السجل، الإعدادات، التبويبات) وسيعود التطبيق جديداً. هل أنت متأكد؟',
                [
                    { text: 'إلغاء', style: 'cancel' },
                    { 
                        text: 'نعم، احذف كل شيء', 
                        style: 'destructive',
                        onPress: () => {
                            onClearData({ clearTabs: true, clearCookies: true, clearSettings: true });
                            onClose();
                        }
                    }
                ]
            );
        } else {
            // Partial Delete
            if (!clearOpts.history && !clearOpts.cookies && !clearOpts.tabs) {
                Alert.alert('تنبيه', 'الرجاء اختيار عنصر لحذفه');
                return;
            }
            Alert.alert(
                'حذف البيانات المحددة',
                'سيتم حذف البيانات المختارة فقط.',
                [
                    { text: 'إلغاء', style: 'cancel' },
                    {
                        text: 'حذف',
                        style: 'destructive',
                        onPress: () => {
                            onClearData({ 
                                clearCookies: clearOpts.history || clearOpts.cookies, 
                                clearTabs: clearOpts.tabs,
                                clearSettings: false // Keep settings in partial mode usually
                            });
                            onClose();
                        }
                    }
                ]
            );
        }
    };

    if (!visible) return null;

    return (
        <Modal transparent visible={visible} onRequestClose={onClose} animationType="none">
            <View style={styles.overlay}>
                <Animated.View style={[styles.container, { transform: [{ translateY: slideAnim }] }]}>

                    {/* Header */}
                    <View style={styles.header}>
                        <Text style={styles.title}>الإعدادات</Text>
                        <TouchableOpacity onPress={onClose} style={styles.doneBtn}>
                            <Text style={styles.doneText}>تم</Text>
                        </TouchableOpacity>
                    </View>

                    <ScrollView style={styles.scrollView} showsVerticalScrollIndicator={false}>

                        {/* Storage Card */}
                        <View style={styles.storageCard}>
                            <View style={styles.storageIconContainer}>
                                <Icon name="database" size={24} color="#fff" />
                            </View>
                            <View style={styles.storageInfo}>
                                <Text style={styles.storageLabel}>مساحة التخزين المستخدمة</Text>
                                <Text style={styles.storageValue}>{storageSize}</Text>
                            </View>
                            <TouchableOpacity onPress={calculateSize}>
                                <Icon name="refresh-cw" size={18} color="#666" />
                            </TouchableOpacity>
                        </View>

                        {/* Search Engine Section */}
                        <Text style={styles.sectionHeader}>محرك البحث</Text>
                        <View style={styles.sectionContainer}>
                            {SEARCH_ENGINES.map((eng, index) => (
                                <TouchableOpacity 
                                    key={eng.name} 
                                    style={[styles.rowItem, index === SEARCH_ENGINES.length - 1 && styles.lastRowItem]}
                                    onPress={() => onSelectEngine(eng.name)}
                                >
                                    <View style={[styles.iconBox, { backgroundColor: eng.color + '20' }]}>
                                        <Icon name={eng.icon} size={18} color={eng.color} />
                                    </View>
                                    <Text style={styles.rowLabel}>{eng.name}</Text>
                                    {currentEngine === eng.name && <Icon name="check" size={20} color="#007AFF" />}
                                </TouchableOpacity>
                            ))}
                        </View>

                        {/* Data Management Section */}
                        <Text style={styles.sectionHeader}>إدارة البيانات</Text>
                        <View style={styles.sectionContainer}>

                            {/* Toggle Row: History & Cookies */}
                            <View style={styles.rowItem}>
                                <View style={[styles.iconBox, { backgroundColor: '#FF980020' }]}>
                                    <Icon name="clock" size={18} color="#FF9800" />
                                </View>
                                <Text style={styles.rowLabel}>السجل والكوكيز</Text>
                                <Switch 
                                    value={clearOpts.history} 
                                    onValueChange={(v) => setClearOpts(p => ({...p, history: v, all: false}))}
                                    trackColor={{true: '#FF9800'}}
                                />
                            </View>

                            {/* Toggle Row: Tabs */}
                            <View style={styles.rowItem}>
                                <View style={[styles.iconBox, { backgroundColor: '#2196F320' }]}>
                                    <Icon name="layers" size={18} color="#2196F3" />
                                </View>
                                <Text style={styles.rowLabel}>التبويبات المفتوحة</Text>
                                <Switch 
                                    value={clearOpts.tabs} 
                                    onValueChange={(v) => setClearOpts(p => ({...p, tabs: v, all: false}))}
                                    trackColor={{true: '#2196F3'}}
                                />
                            </View>

                            {/* Toggle Row: ALL (Nuclear) */}
                            <View style={[styles.rowItem, styles.lastRowItem]}>
                                <View style={[styles.iconBox, { backgroundColor: '#f4433620' }]}>
                                    <Icon name="trash-2" size={18} color="#f44336" />
                                </View>
                                <View style={{flex: 1}}>
                                    <Text style={[styles.rowLabel, {color: '#f44336', fontWeight: 'bold'}]}>حذف كل شيء (تصفير)</Text>
                                    <Text style={{fontSize: 10, color: '#666'}}>يعيد التطبيق جديداً تماماً</Text>
                                </View>
                                <Switch 
                                    value={clearOpts.all} 
                                    onValueChange={(v) => setClearOpts({ history: v, cookies: v, tabs: v, all: v })}
                                    trackColor={{true: '#f44336'}}
                                />
                            </View>

                        </View>

                        {/* Action Buttons */}
                        <TouchableOpacity 
                            style={[styles.actionBtn, { backgroundColor: clearOpts.all ? '#f44336' : '#333' }]}
                            onPress={handleClearAction}
                        >
                            <Text style={[styles.actionBtnText, clearOpts.all && {color: '#fff', fontWeight: 'bold'}]}>
                                {clearOpts.all ? 'تأكيد الحذف الشامل 🗑️' : 'تنفيذ الحذف المحدد'}
                            </Text>
                        </TouchableOpacity>

                        <TouchableOpacity style={styles.secondaryBtn} onPress={onClearCurrentSite}>
                            <Text style={styles.secondaryBtnText}>مسح بيانات الصفحة المفتوحة فقط</Text>
                        </TouchableOpacity>

                        <View style={{height: 100}} />
                    </ScrollView>
                </Animated.View>
            </View>
        </Modal>
    );
};

